/**
 * Unit tests for elicitation/elicitation-guard (#1264 Phase 3).
 *
 * The guard fires on the CC `Elicitation` event and blocks forms whose
 * `form_schema` requests secret-pattern fields. These tests use CC's DOCUMENTED
 * payload shape ({ server_name, tool_name, form_schema }). The prior code read
 * invented field names (elicitation_mode / elicitation_schema / mcp_server_name)
 * and gated on a non-existent `elicitation_mode === 'form'`, so against a real CC
 * payload it never scanned and ALLOWED secret forms — a born-dead security hole.
 * These fixtures use the REAL shape so that regression is caught in CI.
 */

import { describe, it, expect, vi } from 'vitest';
import type { HookInput } from '../../types.js';

vi.mock('../../lib/common.js', async () => {
  const actual = await vi.importActual<typeof import('../../lib/common.js')>('../../lib/common.js');
  return {
    ...actual,
    outputSilentSuccess: vi.fn(() => ({ continue: true, suppressOutput: true })),
    outputBlock: vi.fn((reason: string) => ({ continue: false, stopReason: reason })),
  };
});

import { elicitationGuard } from '../../elicitation/elicitation-guard.js';

function elicitation(overrides: Partial<HookInput> = {}): HookInput {
  return {
    hook_event: 'Elicitation',
    hook_event_name: 'Elicitation',
    tool_name: 'collect_input',
    session_id: 'test',
    tool_input: {},
    project_dir: '/test',
    server_name: 'some-mcp',
    form_schema: { type: 'object', properties: {} },
    ...overrides,
  } as HookInput;
}

describe('elicitation/elicitation-guard (#1264 Phase 3 — real CC payload)', () => {
  it('BLOCKS a form requesting a secret field (api_key)', () => {
    const result = elicitationGuard(elicitation({
      form_schema: { type: 'object', properties: { api_key: { type: 'string' }, name: { type: 'string' } } },
    }));
    expect(result.continue).toBe(false);
    expect(result.stopReason).toContain('api_key');
  });

  it('BLOCKS every secret pattern', () => {
    for (const field of ['password', 'auth_token', 'client_secret', 'db_credential', 'private_key', 'access_key']) {
      const result = elicitationGuard(elicitation({
        form_schema: { type: 'object', properties: { [field]: { type: 'string' } } },
      }));
      expect(result.continue, `should block "${field}"`).toBe(false);
    }
  });

  it('ALLOWS a benign form (no secret fields)', () => {
    const result = elicitationGuard(elicitation({
      form_schema: { type: 'object', properties: { city: { type: 'string' }, region: { type: 'string' } } },
    }));
    expect(result.continue).toBe(true);
  });

  it('ALLOWS when form_schema has no properties or is absent', () => {
    expect(elicitationGuard(elicitation({ form_schema: { type: 'object' } })).continue).toBe(true);
    expect(elicitationGuard(elicitation({ form_schema: undefined })).continue).toBe(true);
  });

  it('reads server_name (real CC field) in the block reason', () => {
    const result = elicitationGuard(elicitation({
      server_name: 'evil-mcp',
      form_schema: { type: 'object', properties: { api_key: { type: 'string' } } },
    }));
    expect(result.stopReason).toContain('evil-mcp');
  });

  it('does NOT key on the obsolete invented fields (regression guard)', () => {
    // A payload carrying ONLY the old invented fields (elicitation_mode / _schema)
    // and no real form_schema must be treated as no-schema → ALLOW. This proves the
    // guard no longer reads the invented shape it was born-dead against.
    const legacy = {
      hook_event: 'Elicitation', tool_name: '', session_id: 't', tool_input: {}, project_dir: '/t',
      elicitation_mode: 'form', elicitation_schema: { properties: { api_key: {} } },
    };
    expect(elicitationGuard(legacy as unknown as HookInput).continue).toBe(true);
  });
});
